import{_ as a,o as i,c as n,a4 as t}from"./chunks/framework.DkKDtR5x.js";const m=JSON.parse('{"title":"Gradle","description":"","frontmatter":{},"headers":[],"relativePath":"backend/gradle.md","filePath":"backend/gradle.md"}'),o={name:"backend/gradle.md"};function r(l,e,d,s,c,p){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="gradle" tabindex="-1">Gradle <a class="header-anchor" href="#gradle" aria-label="Permalink to “Gradle”">​</a></h1><p>Gradle is a powerful, open-source build automation tool primarily used for Java, Kotlin, and Android development.<br> It&#39;s designed to automate the entire software development lifecycle, handling tasks like compiling, packaging, testing, and deploying applications.</p><ul><li>Gradle excels at managing complex projects and offers features like build scans for performance analysis and a configuration cache for faster builds.</li><li>Gradle&#39;s build scripts are written in Groovy or Kotlin DSL, allowing for highly customized build logic.</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>Gradle can be installed via various methods, including downloading binaries or using package managers like SDKMAN!</p><p><a href="https://docs.gradle.org/current/userguide/build_environment.html" target="_blank">gradle properties</a></p><h2 id="dependency-configurations" tabindex="-1">Dependency Configurations <a class="header-anchor" href="#dependency-configurations" aria-label="Permalink to “Dependency Configurations”">​</a></h2><p>Every dependency declared for a Gradle project applies to a specific scope.<br> reference from official doc <a href="https://docs.gradle.org/current/userguide/dependency_configurations.html#sub:what-are-dependency-configurations" target="_blank">here</a></p><p><strong>What&#39;s the difference between implementation, api and compile in Gradle?</strong> Reference article <a href="https://stackoverflow.com/questions/44493378/whats-the-difference-between-implementation-api-and-compile-in-gradle" target="_blank">here</a></p><ul><li>compile is old way</li><li>“implementation” dependency in your module, it will appear only as runtimeClasspath dependency in customer modules.</li><li>“api” dependency in your module, it will appear as both runtimeClasspath and compileClasspath in consumer modules.</li></ul><p><strong>What is the new replacement keyword for deprecated keywords in new gradle?</strong></p><ul><li>compile with <code>implementation</code> (if you don&#39;t need transitivity) or <code>api</code> (if you need transitivity)</li><li>testCompile with <code>testImplementation</code></li><li>debugCompile with <code>debugImplementation</code></li><li>androidTestCompile with <code>androidTestImplementation</code></li><li><code>compileOnly</code> is still valid. <ul><li>It was added in 3.0 to replace provided and not compile.</li><li><code>provided</code> introduced when Gradle didn&#39;t have a configuration name for that use-case and named it after Maven&#39;s provided scope.</li></ul></li></ul><h2 id="buildscript" tabindex="-1">buildscript <a class="header-anchor" href="#buildscript" aria-label="Permalink to “buildscript”">​</a></h2><p><strong>How to download javadocs and sources for jar using Gradle 2.0?</strong></p><p>Reference article <a href="https://stackoverflow.com/questions/28404149/how-to-download-javadocs-and-sources-for-jar-using-gradle-2-0" target="_blank">here</a></p><ul><li><a href="https://docs.gradle.org/current/userguide/building_java_projects.html" target="_blank">Building Java &amp; JVM projects</a></li></ul>',16)])])}const h=a(o,[["render",r]]);export{m as __pageData,h as default};
